def test_gcd_recursion_error_gcd():
    # Test with exact boundary values that trigger the specific bug described.
    a, b = 35, 21
    try:
        result = gcd(a, b)
    except RecursionError:
        result = "recursion error"

    assert result == 7, f"Expected gcd({a}, {b}) to return 7, but got {result}"

def test_gcd_correct_order():
    # Test with boundary values that should work correctly after fixing the bug.
    a, b = 21, 35
    result = gcd(a, b)

    assert result == 7, f"Expected gcd({a}, {b}) to return 7, but got {result}"
